                sum_sq += v * v;
            }
            h_rms.ptr[i] = sqrtf(sum_sq / (float)K + 1e-5f);
        }
        d_rms.upload(h_rms);
        FusedRMSNormMatmulBackward backward;
        backward.init(M, N, K);

        size_t total_bytes = M * K * sizeof(floatX) + N * K * sizeof(floatX) +
