                             M * K * sizeof(float);

        double flops = 4.0 * (double)M * (double)N * (double)K;

        float avg_time_ms =
            bench_kernel([&]() { backward.backward(d_dW, d_dx, d_grad, d_inp, d_weight, d_rms); },
